#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_verbosity_from_flags() {
        assert_eq!(Verbosity::from_flags(true, 0), Verbosity::Quiet);
        assert_eq!(Verbosity::from_flags(false, 0), Verbosity::Normal);
        assert_eq!(Verbosity::from_flags(false, 1), Verbosity::Verbose);
        assert_eq!(Verbosity::from_flags(false, 2), Verbosity::Debug);
        assert_eq!(Verbosity::from_flags(false, 5), Verbosity::Debug); // Caps at Debug
    }

    #[test]
    fn test_quiet_flag_wins() {
        // -q takes precedence over -v
        assert_eq!(Verbosity::from_flags(true, 2), Verbosity::Quiet);
    }

    #[test]
    fn test_verbosity_ordering() {
        assert!(Verbosity::Quiet < Verbosity::Normal);
        assert!(Verbosity::Normal < Verbosity::Verbose);
        assert!(Verbosity::Verbose < Verbosity::Debug);
    }

    #[test]
    fn test_log_level_mapping() {
        assert_eq!(Verbosity::Quiet.log_level(), tracing::Level::ERROR);
        assert_eq!(Verbosity::Normal.log_level(), tracing::Level::WARN);
        assert_eq!(Verbosity::Verbose.log_level(), tracing::Level::INFO);
        assert_eq!(Verbosity::Debug.log_level(), tracing::Level::DEBUG);
    }

    #[test]
    fn test_log_filter_strings() {
        assert_eq!(Verbosity::Quiet.log_filter(), "error");
        assert_eq!(Verbosity::Normal.log_filter(), "warn");
        assert_eq!(Verbosity::Verbose.log_filter(), "info");
        assert_eq!(Verbosity::Debug.log_filter(), "debug");
    }

    #[test]
    fn test_is_quiet() {
        let output = Output::new_piped().with_verbosity(Verbosity::Quiet);
        assert!(output.is_quiet());
        assert!(!output.is_verbose());
        assert!(!output.is_debug());
    }

    #[test]
    fn test_is_verbose() {
        let output = Output::new_piped().with_verbosity(Verbosity::Verbose);
        assert!(!output.is_quiet());
        assert!(output.is_verbose());
        assert!(!output.is_debug());
    }

    #[test]
    fn test_is_debug() {
        let output = Output::new_piped().with_verbosity(Verbosity::Debug);
        assert!(!output.is_quiet());
        assert!(output.is_verbose()); // Debug implies verbose
        assert!(output.is_debug());
    }

    #[test]
    fn test_print_normal_in_quiet_mode() {
        let output = Output::new_piped().with_verbosity(Verbosity::Quiet);
        // This shouldn't panic; just suppress output
        output.print_normal("test");
    }

    #[test]
    fn test_print_verbose_in_normal_mode() {
        let output = Output::new_piped().with_verbosity(Verbosity::Normal);
        // This shouldn't print anything
        output.print_verbose("detail");
    }

    #[test]
    fn test_default_verbosity() {
        assert_eq!(Verbosity::default(), Verbosity::Normal);
    }
}
