echo "Test 7: Quiet wins over verbose" | tee -a "$LOG"
CONFLICT_OUT=$(xf stats -q -v 2>&1)
CONFLICT_LINES=$(echo "$CONFLICT_OUT" | wc -l)
if [ "$CONFLICT_LINES" -le "$QUIET_LINES" ]; then
