integration tests that verify the full search flow.

## Test Categories

### 1. Reranker Loading Tests
```rust
#[test]
fn test_flashrank_loads() {
    let reranker = FlashRankReranker::new(&config).unwrap();
    assert_eq!(reranker.model_name(), "flashrank-nano");
}

#[test]
fn test_mxbai_reranker_loads() {
    let reranker = MxbaiReranker::new(&config).unwrap();
    assert_eq!(reranker.model_name(), "mxbai-rerank-xsmall-v1");
}

#[test]
fn test_reranker_load_with_bad_path_gives_error() {
    let config = RerankerConfig { model_path: "/nonexistent".into() };
    let err = FlashRankReranker::new(&config).unwrap_err();
    assert!(err.to_string().contains("model"), "Error should mention model: {}", err);
}

#[test]
fn test_reranker_from_registry_by_name() {
    let registry = ModelRegistry::new(&global_config);
    let reranker = registry.reranker_by_name("flashrank-nano").unwrap();
    assert_eq!(reranker.model_name(), "flashrank-nano");
}

#[test]
fn test_reranker_unknown_name_gives_error() {
    let registry = ModelRegistry::new(&global_config);
    let err = registry.reranker_by_name("nonexistent-model").unwrap_err();
    assert!(err.to_string().contains("not found") || err.to_string().contains("unknown"));
}
```

### 2. Relevance Ordering Tests
```rust
#[test]
fn test_reranker_ranks_relevant_higher() {
    let reranker = create_test_reranker();
    let query = "best programming language for systems";
    let docs = vec![
        "Rust is a systems programming language focused on safety and performance",
        "Python is great for data science and machine learning",
        "The weather today is sunny with a chance of rain",
        "Recipe: How to make chocolate cake from scratch",
    ];

    let scores = reranker.rerank(query, &docs).unwrap();
    info!("Scores: {:?}", scores);

    // Rust doc should score highest (most relevant to query)
    assert!(scores[0] > scores[2], "Systems lang doc should beat weather");
    assert!(scores[0] > scores[3], "Systems lang doc should beat recipe");
    // Programming doc should beat non-programming
    assert!(scores[1] > scores[3], "Programming doc should beat recipe");
}

#[test]
fn test_reranker_handles_identical_docs() {
    let reranker = create_test_reranker();
    let query = "test query";
    let docs = vec!["same doc", "same doc", "different doc"];
    let scores = reranker.rerank(query, &docs).unwrap();

    // Identical docs should get same score
    assert!((scores[0] - scores[1]).abs() < 0.01,
        "Identical docs should have same score: {} vs {}", scores[0], scores[1]);
}

#[test]
fn test_reranker_query_relevance_sensitivity() {
    // Same docs, different queries → different rankings
    let reranker = create_test_reranker();
    let docs = vec![
        "Rust systems programming safety",
        "Python machine learning data science",
        "JavaScript web frontend React",
    ];

    let rust_scores = reranker.rerank("systems programming memory safety", &docs).unwrap();
    let ml_scores = reranker.rerank("machine learning deep learning", &docs).unwrap();

    assert!(rust_scores[0] > rust_scores[1], "Rust doc should win for systems query");
    assert!(ml_scores[1] > ml_scores[0], "Python doc should win for ML query");
}
```

### 3. Score Calibration Tests
```rust
#[test]
fn test_scores_are_bounded() {
    let reranker = create_test_reranker();
    let query = "test";
    let docs = vec!["relevant doc", "irrelevant doc"];
    let scores = reranker.rerank(query, &docs).unwrap();

    for (i, score) in scores.iter().enumerate() {
        assert!(score.is_finite(), "Score {} should be finite, got {}", i, score);
        // Most rerankers output logits or 0-1 range
        assert!(*score > -100.0 && *score < 100.0,
            "Score {} seems uncalibrated: {}", i, score);
    }
}

#[test]
fn test_scores_are_consistent_across_calls() {
    let reranker = create_test_reranker();
    let query = "test query";
    let docs = vec!["document one", "document two"];

    let scores1 = reranker.rerank(query, &docs).unwrap();
    let scores2 = reranker.rerank(query, &docs).unwrap();

    for (s1, s2) in scores1.iter().zip(scores2.iter()) {
        assert!((s1 - s2).abs() < 1e-5, "Scores should be deterministic: {} vs {}", s1, s2);
    }
}

#[test]
fn test_score_output_length_matches_input() {
    let reranker = create_test_reranker();
    for n in [1, 5, 20, 50] {
        let docs: Vec<String> = (0..n).map(|i| format!("doc {}", i)).collect();
        let doc_refs: Vec<&str> = docs.iter().map(|s| s.as_str()).collect();
        let scores = reranker.rerank("query", &doc_refs).unwrap();
        assert_eq!(scores.len(), n, "Should return exactly {} scores", n);
    }
}
```

